def without_keys(d, *keys, **kwargs):
    """ Return a new dict with the given key(s) removed.

    New dict has d[key] deleted for each supplied key.
    Does not modify the initial dictionary.

    >>> without_keys({'x': 1, 'y': 2}, 'y')
    {'x': 1}
    >>> without_keys({'x': 1, 'y': 2}, 'y', 'x')
    {}
    >>> without_keys({'x': 1}, 'y') # Ignores missing keys
    {'x': 1}
    """
    factory = _get_factory(without_keys, kwargs)
    d2 = factory()

    if len(keys) < len(d) * .6:
        d2.update(d)
        for key in keys:
            if key in d2:
                del d2[key]
    else:
        remaining = set(d)
        remaining.difference_update(keys)
        for k in remaining:
            d2[k] = d[k]
    return d2

def prepend_item(el, seq):
    """ Add el to beginning of (possibly infinite) sequence seq.

    >>> list(prepend_item(1, [2, 3]))
    [1, 2, 3]
    """
    return itertools.chain([el], seq)

def yield_last(n, iterable):
    """Return an iterator over the final *n* items of *iterable*.

    >>> t = yield_last(3, 'ABCDEFG')
    >>> list(t)
    ['E', 'F', 'G']

    """
    try:
        size = len(iterable)
    except TypeError:
        return iter(deque(iterable, maxlen=n))
    else:
        return islice(iterable, max(0, size - n), None)
